-- ========================================================================
-- Opticedge Credit — bulk reference data (MySQL 8+)
-- Majina halisi ya brands/models (specs za soko) + maduka ya demo Tanzania.
-- ========================================================================
-- Kabla: php artisan migrate && php artisan db:seed --class=RolesAndPermissionsSeeder
-- Import: mysql -u USER -p DATABASE < database/sql/oe_bulk_reference_data.sql
--
-- Ikiwa brands/slugs tayari zipo (mf. Samsung), futa rekodi za majaribito au
-- badilisha slugs kwenye generate_oe_bulk_reference_data.php kisha zalisha upya.
--
-- Users: INSERT ... ON DUPLICATE KEY UPDATE (barua pepe / employee_code) —
--   unaweza ku-import tena bila #1062 duplicate email.
--
-- Nenosiri: Opticedge@2026 (admins 3), DealerOwner@2026 (owners 15).
-- Regenerate: php database/sql/generate_oe_bulk_reference_data.php
-- ========================================================================

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS=0;

-- ---------------------------------------------------------------- dealers

-- ---------------------------------------------------------------- brands

-- ---------------------------------------------------------------- phone_models

-- ---------------------------------------------------------------- users
ON DUPLICATE KEY UPDATE
  `dealer_id` = VALUES(`dealer_id`),
  `joined_at` = VALUES(`joined_at`),
  `role` = VALUES(`role`),
  `name` = VALUES(`name`),
  `phone` = VALUES(`phone`),
  `employee_code` = VALUES(`employee_code`),
  `is_active` = VALUES(`is_active`),
  `email_verified_at` = VALUES(`email_verified_at`),
  `password` = VALUES(`password`),
  `two_factor_secret` = VALUES(`two_factor_secret`),
  `two_factor_recovery_codes` = VALUES(`two_factor_recovery_codes`),
  `two_factor_confirmed_at` = VALUES(`two_factor_confirmed_at`),
  `remember_token` = VALUES(`remember_token`),
  `updated_at` = VALUES(`updated_at`),
  `avatar_url` = VALUES(`avatar_url`);

UPDATE `dealers` SET `owner_user_id` = (SELECT `id` FROM `users` WHERE `email` = 'owner.dmo-tz-01@opticedgecredity.com' LIMIT 1) WHERE `code` = 'DMO-TZ-001';
