SELECT r.`id`, 'App\\Models\\User', u.`id` FROM `roles` r CROSS JOIN `users` u
WHERE r.`name` = 'admin' AND r.`guard_name` = 'web'
AND u.`email` IN ('sql.superadmin@opticedgecredity.com','sql.opsadmin@opticedgecredity.com','sql.finance@opticedgecredity.com');

SELECT r.`id`, 'App\\Models\\User', u.`id` FROM `roles` r CROSS JOIN `users` u
WHERE r.`name` = 'owner' AND r.`guard_name` = 'web'
AND u.`email` LIKE 'owner.dmo-tz-%@opticedgecredity.com';

SET FOREIGN_KEY_CHECKS=1;

